import React, { useState, useEffect } from 'react';
import { marketAPI } from '../api';

export default function MarketPrices() {
  const [prices, setPrices] = useState([]);
  const [msp, setMsp] = useState([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => { fetchPrices(); fetchMSP(); }, []);

  const fetchPrices = async () => {
    setLoading(true);
    try {
      const res = await marketAPI.prices({});
      setPrices(res.data.prices || []);
    } catch (e) { console.error(e); } finally { setLoading(false); }
  };

  const fetchMSP = async () => {
    try {
      const res = await marketAPI.msp();
      setMsp(res.data.msp || []);
    } catch (e) { console.error(e); }
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
      <div style={styles.card}>
        <div style={styles.header}><div style={styles.title}>📈 Live Market Prices</div>
          <span style={{ fontSize: '0.8rem', color: '#9e9e9e' }}>Source: Agmarknet Demo • Today</span></div>
        {loading ? <div style={{ textAlign: 'center', padding: 30 }}>Loading...</div> : (
          <table style={styles.table}>
            <thead><tr>{['Crop','Market','Modal Price','Range','Change'].map(h =>
              <th key={h} style={styles.th}>{h}</th>)}</tr></thead>
            <tbody>
              {prices.map((r, i) => (
                <tr key={i} style={{ borderBottom: '1px solid #f5f5f5' }}>
                  <td style={styles.td}><span style={styles.pill}>{r.crop}</span></td>
                  <td style={{ ...styles.td, color: '#666' }}>{r.market}</td>
                  <td style={{ ...styles.td, fontWeight: 600 }}>₹{r.modalPrice?.toLocaleString()}</td>
                  <td style={{ ...styles.td, fontSize: '0.78rem', color: '#9e9e9e' }}>₹{r.minPrice}–{r.maxPrice}</td>
                  <td style={{ ...styles.td, color: r.trend === 'UP' ? '#2e7d32' : r.trend === 'DOWN' ? '#c62828' : '#9e9e9e', fontWeight: 600 }}>{r.change}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
      {msp.length > 0 && (
        <div style={styles.card}>
          <div style={styles.title}>🏛️ MSP 2023-24 (Government Minimum Support Prices)</div>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 10, marginTop: 12 }}>
            {msp.map((m, i) => (
              <div key={i} style={{ background: '#f9fbe7', borderRadius: 8, padding: '10px 14px', display: 'flex', justifyContent: 'space-between', border: '1px solid #dce775' }}>
                <span style={{ fontSize: '0.85rem', color: '#555' }}>{m.crop}</span>
                <span style={{ fontSize: '0.9rem', fontWeight: 600, color: '#2e7d32' }}>₹{m.msp}</span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

const styles = {
  card: { background: '#fff', borderRadius: 14, padding: '18px 20px', border: '1px solid #e0e0e0' },
  header: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14 },
  title: { fontWeight: 700, fontSize: '0.95rem', color: '#1b5e20', marginBottom: 0 },
  table: { width: '100%', borderCollapse: 'collapse', fontSize: '0.85rem' },
  th: { textAlign: 'left', padding: '8px 10px', color: '#888', fontWeight: 600, fontSize: '0.75rem', textTransform: 'uppercase', letterSpacing: '0.3px', borderBottom: '2px solid #e8f5e9' },
  td: { padding: '10px 10px' },
  pill: { background: '#f5f5f5', padding: '3px 10px', borderRadius: 10, fontSize: '0.8rem' },
};
